package workloadmanager

import (
	"context"
	"fmt"
	"net/http"
	"os"
	"path/filepath"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/volcano-sh/agentcube/pkg/store"
	corev1 "k8s.io/api/core/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/runtime"
	"k8s.io/client-go/dynamic"
	"k8s.io/client-go/dynamic/dynamicinformer"
	"k8s.io/client-go/informers"
	"k8s.io/client-go/kubernetes"
	listersv1 "k8s.io/client-go/listers/core/v1"
	"k8s.io/client-go/rest"
	"k8s.io/client-go/tools/cache"
	"k8s.io/client-go/tools/clientcmd"
	"k8s.io/utils/ptr"
)

type Server struct {
	config            *Config
	router            *gin.Engine
	httpServer        *http.Server
	k8sClient         *K8sClient
	sandboxController *SandboxReconciler
	tokenCache        *TokenCache
	informers         *Informers
	storeClient       store.Store
	wg                sync.WaitGroup
}

func NewServer(cfg *Config) (*Server, error) {
	k8sClient, err := NewK8sClient()
	if err != nil {
		return nil, err
	}

	informers, err := NewInformers(k8sClient)
	if err != nil {
		return nil, err
	}

	s := &Server{
		config:      cfg,
		k8sClient:   k8sClient,
		informers:   informers,
		tokenCache:  NewTokenCache(1000, 5*time.Minute),
		storeClient: store.Storage(),
	}

	s.sandboxController = NewSandboxReconciler(s.k8sClient.dynamicClient, s.k8sClient.scheme)
	s.setupRoutes()

	return s, nil
}

func (s *Server) setupRoutes() {
	if s.config.EnableTLS {
		gin.SetMode(gin.ReleaseMode)
	}

	s.router = gin.New()
	s.router.Use(gin.Recovery())

	s.router.GET("/health", s.handleHealth)

	v1 := s.router.Group("/v1")
	{
		agentRuntime := v1.Group("/agent-runtime")
		if s.config.EnableAuth {
			agentRuntime.Use(s.authMiddleware())
		}
		agentRuntime.POST("", s.handleAgentRuntimeCreate)
		agentRuntime.DELETE("/sessions/:sessionId", s.handleDeleteSandbox)

		codeInterpreter := v1.Group("/code-interpreter")
		if s.config.EnableAuth {
			codeInterpreter.Use(s.authMiddleware())
		}
		codeInterpreter.POST("", s.handleCodeInterpreterCreate)
		codeInterpreter.DELETE("/sessions/:sessionId", s.handleDeleteSandbox)
	}
}

func (s *Server) Run(ctx context.Context) error {
	s.httpServer = &http.Server{
		Addr:    ":" + s.config.Port,
		Handler: s.router,
	}

	s.wg.Add(1)
	go func() {
		defer s.wg.Done()
		s.informers.Start(ctx)
	}()

	s.wg.Add(1)
	go func() {
		defer s.wg.Done()
		gc := newGarbageCollector(s.k8sClient, s.storeClient, 15*time.Second)
		gc.Run(ctx)
	}()

	errCh := make(chan error, 1)
	go func() {
		var err error
		if s.config.EnableTLS && s.config.TLSCert != "" && s.config.TLSKey != "" {
			err = s.httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
		} else {
			err = s.httpServer.ListenAndServe()
		}
		errCh <- err
	}()

	select {
	case <-ctx.Done():
		shutdownCtx, cancel := context.WithTimeout(context.Background(), 15*time.Second)
		defer cancel()
		_ = s.httpServer.Shutdown(shutdownCtx)
		s.wg.Wait()
		if s.storeClient != nil {
			_ = s.storeClient.Close()
		}
		return nil
	case err := <-errCh:
		if err != nil && err != http.ErrServerClosed {
			return err
		}
		return nil
	}
}

func (s *Server) WaitForBackgroundWorkers() {
	s.wg.Wait()
}

func (s *Server) CloseStore() error {
	if s.storeClient != nil {
		return s.storeClient.Close()
	}
	return nil
}

type Informers struct {
	dynamicInformer cache.SharedIndexInformer
	podInformer     cache.SharedIndexInformer
	podLister       listersv1.PodLister
}

func NewInformers(k8sClient *K8sClient) (*Informers, error) {
	podInformer := k8sClient.informerFactory.Core().V1().Pods().Informer()

	return &Informers{
		dynamicInformer: k8sClient.dynamicInformer.ForResource(SandboxGVR).Informer(),
		podInformer:     podInformer,
		podLister:       k8sClient.informerFactory.Core().V1().Pods().Lister(),
	}, nil
}

func (i *Informers) Start(ctx context.Context) {
	go i.dynamicInformer.Run(ctx.Done())
	go i.podInformer.Run(ctx.Done())
}

type ClientCache struct {
	mu      sync.RWMutex
	clients map[string]kubernetes.Interface
	maxSize int
}

func NewClientCache(maxSize int) *ClientCache {
	return &ClientCache{
		clients: make(map[string]kubernetes.Interface),
		maxSize: maxSize,
	}
}

func (c *ClientCache) Get(key string) kubernetes.Interface {
	c.mu.RLock()
	defer c.mu.RUnlock()
	return c.clients[key]
}

func (c *ClientCache) Set(key string, client kubernetes.Interface) {
	c.mu.Lock()
	defer c.mu.Unlock()
	if len(c.clients) >= c.maxSize {
		for k := range c.clients {
			delete(c.clients, k)
			break
		}
	}
	c.clients[key] = client
}

type K8sClient struct {
	clientset       *kubernetes.Clientset
	dynamicClient   dynamic.Interface
	scheme          *runtime.Scheme
	baseConfig      *rest.Config
	clientCache     *ClientCache
	dynamicInformer dynamicinformer.DynamicSharedInformerFactory
	informerFactory informers.SharedInformerFactory
	podInformer     cache.SharedIndexInformer
	podLister       listersv1.PodLister
}

func NewK8sClient() (*K8sClient, error) {
	config, err := rest.InClusterConfig()
	if err != nil {
		kubeconfig := filepath.Join(os.Getenv("HOME"), ".kube", "config")
		config, err = clientcmd.BuildConfigFromFlags("", kubeconfig)
		if err != nil {
			return nil, fmt.Errorf("failed to get kubeconfig: %w", err)
		}
	}

	config.QPS = 50
	config.Burst = 100

	clientset, err := kubernetes.NewForConfig(config)
	if err != nil {
		return nil, fmt.Errorf("failed to create clientset: %w", err)
	}

	dynamicClient, err := dynamic.NewForConfig(config)
	if err != nil {
		return nil, fmt.Errorf("failed to create dynamic client: %w", err)
	}

	scheme := runtime.NewScheme()
	_ = corev1.AddToScheme(scheme)
	_ = metav1.AddToScheme(scheme)

	informerFactory := informers.NewSharedInformerFactory(clientset, time.Minute)
	podInformer := informerFactory.Core().V1().Pods().Informer()

	dynamicInformer := dynamicinformer.NewDynamicSharedInformerFactory(dynamicClient, time.Minute)

	return &K8sClient{
		clientset:       clientset,
		dynamicClient:   dynamicClient,
		scheme:          scheme,
		baseConfig:      config,
		clientCache:     NewClientCache(100),
		dynamicInformer: dynamicInformer,
		informerFactory: informerFactory,
		podInformer:     podInformer,
		podLister:       informerFactory.Core().V1().Pods().Lister(),
	}, nil
}

