	mu            sync.RWMutex
}

func NewSandboxReconciler(dynamicClient dynamic.Interface, scheme *runtime.Scheme) *SandboxReconciler {
	return &SandboxReconciler{
		dynamicClient: dynamicClient,
		scheme:        scheme,
		watchers:      make(map[types.NamespacedName]chan SandboxStatusUpdate),
	}
}

func (r *SandboxReconciler) WatchSandbox(ctx context.Context, name, namespace string) <-chan SandboxStatusUpdate {
	key := types.NamespacedName{Name: name, Namespace: namespace}
	ch := make(chan SandboxStatusUpdate, 1)

	r.mu.Lock()
	r.watchers[key] = ch
	r.mu.Unlock()

	go func() {
		<-ctx.Done()
		r.mu.Lock()
		delete(r.watchers, key)
		r.mu.Unlock()
	}()

	return ch
}

func (r *SandboxReconciler) StopWatch(name, namespace string) {
	key := types.NamespacedName{Name: name, Namespace: namespace}
	r.mu.Lock()
	delete(r.watchers, key)
	r.mu.Unlock()
}

func (r *SandboxReconciler) NotifyUpdate(name, namespace string, sandbox *Sandbox) {
	key := types.NamespacedName{Name: name, Namespace: namespace}
	status := getSandboxStatus(sandbox)
	if status == "running" {
		r.mu.RLock()
		ch, exists := r.watchers[key]
		r.mu.RUnlock()

		if exists {
			select {
			case ch <- SandboxStatusUpdate{Sandbox: sandbox}:
			default:
				fmt.Printf("Warning: channel full for sandbox %s, status update dropped\n", key.String())
			}
