package router

import (
	"fmt"
	"net/http"
	"net/http/httputil"
	"net/url"
	"strings"

	"github.com/gin-gonic/gin"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

func (s *Server) proxyRequest(c *gin.Context, sandbox *types.SandboxInfo, path string, kind string) {
	var endpoint string
	for _, ep := range sandbox.EntryPoints {
		if strings.HasPrefix(path, ep.Path) || ep.Path == "/" {
			endpoint = ep.Endpoint
			break
		}
	}

	if endpoint == "" {
		if len(sandbox.EntryPoints) > 0 {
			endpoint = sandbox.EntryPoints[0].Endpoint
		}
	}

	if endpoint == "" {
		c.JSON(http.StatusNotFound, gin.H{"error": "no entry point found for sandbox"})
		return
	}

	targetURL, err := url.Parse(endpoint)
	if err != nil {
		klog.Errorf("Failed to parse endpoint URL %s: %v", endpoint, err)
		c.JSON(http.StatusInternalServerError, gin.H{"error": "internal server error"})
		return
	}

	if targetURL.Scheme == "" && sandbox.EntryPoints != nil && len(sandbox.EntryPoints) > 0 {
		for _, ep := range sandbox.EntryPoints {
			if ep.Endpoint == endpoint {
				if ep.Protocol != "" {
					targetURL, _ = url.Parse(strings.ToLower(ep.Protocol) + "://" + endpoint)
				}
				break
			}
		}
	}

	proxy := httputil.NewSingleHostReverseProxy(targetURL)
	proxy.Transport = s.httpTransport

	proxy.Director = func(req *http.Request) {
		req.URL.Scheme = targetURL.Scheme
		req.URL.Host = targetURL.Host
		req.URL.Path = s.normalizePath(path)
		req.URL.RawPath = ""
		req.Host = targetURL.Host

		req.Header.Set("X-Forwarded-For", c.ClientIP())
		req.Header.Set("X-Forwarded-Proto", "http")
		if c.Request.TLS != nil {
			req.Header.Set("X-Forwarded-Proto", "https")
		}
		req.Header.Set("X-Forwarded-Host", c.Request.Host)

		if len(sandbox.SandboxID) > 0 {
			req.Header.Set("X-Sandbox-ID", sandbox.SandboxID)
		}

		if kind == types.SandboxKind || kind == types.SandboxClaimsKind {
			token, err := s.jwtManager.GenerateToken(map[string]interface{}{
				"session_id": sandbox.SessionID,
				"sandbox_id": sandbox.SandboxID,
				"namespace":  sandbox.SandboxNamespace,
			})
			if err != nil {
				klog.Errorf("Failed to generate JWT token: %v", err)
			} else if token != "" {
				req.Header.Set("Authorization", fmt.Sprintf("Bearer %s", token))
			}
		}
	}

	proxy.ModifyResponse = func(resp *http.Response) error {
		resp.Header.Set("x-agentcube-session-id", sandbox.SessionID)
		return nil
	}

	proxy.ErrorHandler = func(w http.ResponseWriter, r *http.Request, err error) {
		klog.Errorf("Proxy error: %v", err)
		errMsg := err.Error()
		if strings.Contains(errMsg, "connection refused") {
			w.WriteHeader(http.StatusBadGateway)
			w.Write([]byte(`{"error":"sandbox unreachable"}`))
			return
		}
		if strings.Contains(errMsg, "timeout") {
			w.WriteHeader(http.StatusGatewayTimeout)
			w.Write([]byte(`{"error":"sandbox timeout"}`))
			return
		}
		w.WriteHeader(http.StatusBadGateway)
		w.Write([]byte(`{"error":"sandbox unreachable"}`))
	}

	proxy.ServeHTTP(c.Writer, c.Request)
}

