package router

import (
	"context"
	"net/http"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
	"golang.org/x/net/http2"
	"golang.org/x/net/http2/h2c"

	"github.com/volcano-sh/agentcube/pkg/store"
)

type Server struct {
	config         *Config
	engine         *gin.Engine
	httpServer     *http.Server
	sessionManager SessionManager
	storeClient    store.Store
	httpTransport  *http.Transport
	jwtManager     *JWTManager
}

func NewServer(cfg *Config) (*Server, error) {
	if cfg.Debug {
		gin.SetMode(gin.DebugMode)
	} else {
		gin.SetMode(gin.ReleaseMode)
	}

	maxConcurrent := cfg.MaxConcurrentRequests
	if maxConcurrent <= 0 {
		maxConcurrent = 1000
	}
	cfg.MaxConcurrentRequests = maxConcurrent

	storeClient := store.Storage()
	sessionManager, err := NewSessionManager(storeClient)
	if err != nil {
		return nil, err
	}

	jwtManager, err := NewJWTManager()
	if err != nil {
		return nil, err
	}

	httpTransport := &http.Transport{
		IdleConnTimeout:     0,
		DisableCompression:  false,
		MaxIdleConnsPerHost: 100,
	}
	http2.ConfigureTransports(httpTransport)

	s := &Server{
		config:         cfg,
		storeClient:    storeClient,
		sessionManager: sessionManager,
		httpTransport:  httpTransport,
		jwtManager:     jwtManager,
	}

	s.setupRoutes()

	return s, nil
}

func (s *Server) setupRoutes() {
	s.engine = gin.New()

	s.engine.GET("/health/live", s.handleHealthLive)
	s.engine.GET("/health/ready", s.handleHealthReady)

	apiGroup := s.engine.Group("/v1")
	apiGroup.Use(gin.Logger(), gin.Recovery(), s.concurrencyLimitMiddleware())
	apiGroup.GET("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", s.handleAgentInvoke)
	apiGroup.POST("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", s.handleAgentInvoke)
	apiGroup.GET("/namespaces/:namespace/code-interpreters/:name/invocations/*path", s.handleCodeInterpreterInvoke)
	apiGroup.POST("/namespaces/:namespace/code-interpreters/:name/invocations/*path", s.handleCodeInterpreterInvoke)
}

func (s *Server) Run(ctx context.Context) error {
	h2s := &http2.Server{}
	s.httpServer = &http.Server{
		Addr:         ":" + s.config.Port,
		Handler:      h2c.NewHandler(s.engine, h2s),
		ReadTimeout:  30 * time.Second,
		IdleTimeout:  90 * time.Second,
	}

	errCh := make(chan error, 1)
	go func() {
		var err error
		if s.config.EnableTLS && s.config.TLSCert != "" && s.config.TLSKey != "" {
			err = s.httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
		} else {
			err = s.httpServer.ListenAndServe()
		}
		if err != nil && err != http.ErrServerClosed {
			errCh <- err
		}
	}()

	select {
	case err := <-errCh:
		return err
	case <-ctx.Done():
		return s.Shutdown()
	}
}

func (s *Server) Shutdown() error {
	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()
	return s.httpServer.Shutdown(ctx)
}

func (s *Server) normalizePath(path string) string {
	if !strings.HasPrefix(path, "/") {
		path = "/" + path
	}
	return path
}

