)

type contextKey string

const (
	contextKeyUserToken          contextKey = "userToken"
	contextKeyServiceAccount     contextKey = "serviceAccount"
	contextKeyServiceAccountName contextKey = "serviceAccountName"
	contextKeyNamespace          contextKey = "namespace"
)

func (s *Server) authMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.JSON(http.StatusUnauthorized, ErrorResponse{Message: "Missing authorization header"})
			c.Abort()
			return
		}

		parts := strings.Split(authHeader, " ")
		if len(parts) != 2 || parts[0] != "Bearer" {
			c.JSON(http.StatusUnauthorized, ErrorResponse{Message: "Invalid authorization header format"})
			c.Abort()
			return
		}

		token := parts[1]

		authenticated, serviceAccount, namespace, ok := s.tokenCache.Get(token)
		if ok && authenticated {
			c.Set(string(contextKeyUserToken), token)
			c.Set(string(contextKeyServiceAccount), serviceAccount)
			c.Set(string(contextKeyNamespace), namespace)
			serviceAccountName := extractServiceAccountName(serviceAccount)
			c.Set(string(contextKeyServiceAccountName), serviceAccountName)
			c.Next()
			return
		}

		authResp, err := s.k8sClient.clientset.AuthenticationV1().TokenReviews().Create(c.Request.Context(), &authenticationv1.TokenReview{
			Spec: authenticationv1.TokenReviewSpec{
				Token: token,
			},
		}, metav1.CreateOptions{})
		if err != nil {
			klog.Errorf("TokenReview failed: %v", err)
			c.JSON(http.StatusUnauthorized, ErrorResponse{Message: "Token validation failed"})
			c.Abort()
			return
		}

		if !authResp.Status.Authenticated {
			c.JSON(http.StatusUnauthorized, ErrorResponse{Message: "Invalid token"})
			c.Abort()
			return
		}

		username := authResp.Status.User.Username
		serviceAccountName := extractServiceAccountName(username)
		ns := extractNamespace(username)

		s.tokenCache.Set(token, true, username, ns)

		c.Set(string(contextKeyUserToken), token)
		c.Set(string(contextKeyServiceAccount), username)
		c.Set(string(contextKeyNamespace), ns)
		c.Set(string(contextKeyServiceAccountName), serviceAccountName)

		c.Next()
	}
}

func extractServiceAccountName(username string) string {
	parts := strings.Split(username, ":")
	if len(parts) >= 4 && parts[0] == "system" && parts[1] == "serviceaccount" {
		return parts[3]
	}
	return ""
}

func extractNamespace(username string) string {
	parts := strings.Split(username, ":")
	if len(parts) >= 4 && parts[0] == "system" && parts[1] == "serviceaccount" {
		return parts[2]
	}
	return ""
}

func (s *Server) GetUserClient(c *gin.Context) (string, string, string) {
	token, _ := c.Get(string(contextKeyUserToken))
	namespace, _ := c.Get(string(contextKeyNamespace))
	serviceAccountName, _ := c.Get(string(contextKeyServiceAccountName))
	return token.(string), namespace.(string), serviceAccountName.(string)
}

func (s *Server) GetOrCreateUserK8sClient(namespace, serviceAccountName string, token string) {
	cacheKey := fmt.Sprintf("%s:%s", namespace, serviceAccountName)
	_ = cacheKey
}

