type garbageCollector struct {
	k8sClient   *K8sClient
	storeClient store.Store
	interval    time.Duration
}

func newGarbageCollector(k8sClient *K8sClient, storeClient store.Store, interval time.Duration) *garbageCollector {
	return &garbageCollector{
		k8sClient:   k8sClient,
		storeClient: storeClient,
		interval:    interval,
	}
}

func (gc *garbageCollector) Run(ctx context.Context) {
	ticker := time.NewTicker(gc.interval)
	defer ticker.Stop()

	for {
		select {
		case <-ctx.Done():
			return
		case <-ticker.C:
			gc.collect(ctx)
		}
	}
}

func (gc *garbageCollector) collect(ctx context.Context) {
	now := time.Now()

	expired, err := gc.storeClient.ListExpiredSandboxes(ctx, now, 16)
	if err != nil {
		klog.Errorf("Failed to list expired sandboxes: %v", err)
		return
	}

	for _, sandbox := range expired {
		klog.Infof("Cleaning up expired sandbox: %s", sandbox.SessionID)
		if err := gc.storeClient.DeleteSandboxBySessionID(ctx, sandbox.SessionID); err != nil {
			klog.Errorf("Failed to delete expired sandbox %s: %v", sandbox.SessionID, err)
		}
	}

	inactive, err := gc.storeClient.ListInactiveSandboxes(ctx, now.Add(-DefaultSandboxIdleTimeout), 16)
	if err != nil {
		klog.Errorf("Failed to list inactive sandboxes: %v", err)
		return
	}

	for _, sandbox := range inactive {
		klog.Infof("Cleaning up inactive sandbox: %s", sandbox.SessionID)
		if err := gc.storeClient.DeleteSandboxBySessionID(ctx, sandbox.SessionID); err != nil {
			klog.Errorf("Failed to delete inactive sandbox %s: %v", sandbox.SessionID, err)
		}
	}
}

